1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const FIRST_INSURANCE_MULTIPLIER = 1.1;
6	const CURSED_MULTIPLIER = 1.5;
7	const HIGH_ENCHANTMENT_MULTIPLIER = 1.3;
8	const LOYALTY_MULTIPLIER = 0.8;
9	const LOYALTY_YEARS_THRESHOLD = 2;
10	const ADMIN_FEE = 5;
11	
12	// Three alike pieces of a "building-block" item (rune, moonstone, …) pool
13	// to a single unit priced at this fixed tier, irrespective of the per-piece
14	// BASE_PRICE. The tier coincidentally equals amulet's base price today but
15	// is conceptually a separate pricing rule from the per-item ladder.
16	const BUILDING_BLOCK_PRICE = 60;
17	
18	const BASE_PRICE: Record<string, number> = {
19	  sword: 100,
20	  staff: 80,
21	  amulet: 60,
22	  potion: 40,
23	  rune: 25,
24	  moonstone: 25,
25	};
26	
27	const POOLED_TYPES = new Set(["rune", "moonstone"]);
28	
29	function itemModifierMultiplier(item: Item): number {
30	  const cursed = item.cursed ? CURSED_MULTIPLIER : 1;
31	  const highEnchantment =
32	    (item.enchantment ?? 0) >= 5 ? HIGH_ENCHANTMENT_MULTIPLIER : 1;
33	  return cursed * highEnchantment;
34	}
35	
36	// MHPCO always rounds the euro value of a discounted/loaded price upward
37	// (in the office's favour). The toFixed(10) step strips IEEE-754 drift so
38	// values that are mathematically integer (e.g. 100 × 1.10 = 110) don't get
39	// bumped up a euro by a 110.00000000000001 representation.
40	function ceilInMhpcoFavor(value: number): number {
41	  return Math.ceil(Number(value.toFixed(10)));
42	}
43	
44	// Sum of per-item base prices (with item-attribute multipliers applied)
45	// for a single quote. Building-block items (rune today, moonstone in cycle
46	// 13) are pooled in groups of three at BUILDING_BLOCK_PRICE; leftovers fall
47	// back to the per-piece BASE_PRICE.
48	function quoteItemsSubtotal(items: Item[]): number {
49	  let subtotal = 0;
50	  const pooledCounts = new Map<string, number>();
51	  for (const item of items) {
52	    if (POOLED_TYPES.has(item.type)) {
53	      pooledCounts.set(item.type, (pooledCounts.get(item.type) ?? 0) + 1);
54	    } else {
55	      subtotal += BASE_PRICE[item.type] * itemModifierMultiplier(item);
56	    }
57	  }
58	  for (const [type, count] of pooledCounts) {
59	    const buildingBlocks = Math.floor(count / 3);
60	    const loose = count % 3;
61	    subtotal += buildingBlocks * BUILDING_BLOCK_PRICE + loose * BASE_PRICE[type];
62	  }
63	  return subtotal;
64	}
65	
66	export function runScenario(scenario: unknown): unknown {
67	  const { customer, steps } = scenario as Scenario;
68	  const itemsTotal = quoteItemsSubtotal(steps[0].items);
69	  const loyaltyMultiplier =
70	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? LOYALTY_MULTIPLIER : 1;
71	  const premium =
72	    ceilInMhpcoFavor(itemsTotal * loyaltyMultiplier * FIRST_INSURANCE_MULTIPLIER) +
73	    ADMIN_FEE;
74	  return { results: [{ premium }] };
75	}
